import React, { useEffect, useState } from 'react';
import { useLocation } from 'react-router-dom';
import axios from 'axios';

function Products() {
  const location = useLocation();
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const category = params.get('category');
    const collection = params.get('collection');

    async function load() {
      setLoading(true);
      try {
        const resp = await axios.get('/api/products', { params: { category, collection } });
        setProducts(resp.data.products || resp.data);
      } catch (err) {
        console.error(err);
        setProducts([]);
      } finally {
        setLoading(false);
      }
    }

    load();
  }, [location.search]);

  return (
    <div className="products-page">
      <h2>Products</h2>
      <p className="filter-summary">Showing: {new URLSearchParams(location.search).toString() || 'All'}</p>

      {loading ? (
        <p>Loading...</p>
      ) : (
        <div className="products-grid">
          {products.length === 0 ? (
            <p>No products found.</p>
          ) : (
            products.map(p => (
              <div key={p.product_id} className="product-card">
                <img src={p.image_url || '/product-image.jpg'} alt={p.name} />
                <p className="category">{p.category}</p>
                <h3>{p.name}</h3>
                <p className="price">${p.price}</p>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
}

export default Products;
